/**
 * Regenerate plan_weeks and plan_days from the currently ACTIVE
Planner config. Logged workouts and body measurements are PRESERVED.
Reset-undo snapshots are dropped because their plan_day ids no longer
match. Workout plan_day_id FKs are best-effort rebound to the new
plan_day with the same date; workouts whose date no longer falls
within the regenerated plan get plan_day_id = NULL.

 */
export const ApplyPlannerConfigResponse = zod
  .object({
    weeksSeeded: zod.number(),
    daysSeeded: zod.number(),
    workoutsPreserved: zod
      .number()
      .describe(
        "Count of logged workouts that survived the apply (i.e. were not wiped). Their plan_day_id FKs are best-effort re-pointed to the new plan_day with the same date; rows whose date no longer falls within the regenerated plan are kept but get plan_day_id = NULL so the runner doesn't lose history.",
      ),
    measurementsPreserved: zod.number(),
    undoSnapshotsWiped: zod.number(),
    totalWeeks: zod.number(),
  })
  .describe(
    "Result of regenerating plan_weeks and plan_days from the saved Planner config. Workouts and measurements are preserved (not wiped); reset undo snapshots are dropped because their plan_day ids no longer match.",
  );

/**
 * Task #370. In-place re-pace of the already-applied campaign.
Updates `applied_starting_pace_sec` on the most-recently-applied
planner_configs row AND mirrors the new value back into the source
`starting_pace_sec` column, then runs the pace-target backfill to
regenerate uncustomized run cards in place. Workouts, body
measurements, race results, race-week checklist, and ANY /plan-
edited day cards (where runtime values diverge from prior seed)
are preserved. Use this instead of /planner/apply when the only
thing that needs to change is the starting easy pace — apply
TRUNCATEs plan_days and loses every per-day customization.

 */
export const updateAppliedStartingPaceBodyStartingPaceSecMin = 360;
export const updateAppliedStartingPaceBodyStartingPaceSecMax = 1500;

export const updateAppliedStartingPaceBodyGoalEndingPaceSecMin = 360;
export const updateAppliedStartingPaceBodyGoalEndingPaceSecMax = 1500;

export const UpdateAppliedStartingPaceBody = zod.object({
  startingPaceSec: zod
    .number()
    .min(updateAppliedStartingPaceBodyStartingPaceSecMin)
    .max(updateAppliedStartingPaceBodyStartingPaceSecMax)
    .nullish()
    .describe(
      "Runner's starting easy pace in seconds\/mile. When this key is\nOMITTED, the applied row's existing starting pace is left\nuntouched (so a runner can patch only the goal anchor\nwithout clobbering their start, and vice versa). Present\nwith null clears the override, so the generator falls back\nto the first block's recipe easy pace (Task #367) — or to\nthe fixed DEFAULT_STARTING_PACE_SEC when a goal anchor is\nset (Task #373). Present with an integer writes it.\n",
    ),
  goalEndingPaceSec: zod
    .number()
    .min(updateAppliedStartingPaceBodyGoalEndingPaceSecMin)
    .max(updateAppliedStartingPaceBodyGoalEndingPaceSecMax)
    .nullish()
    .describe(
      "Task #373. Optional goal ending easy pace (sec\/mi). When this\nkey is OMITTED, the applied row's existing goal value is left\nuntouched (legacy single-field callers stay valid). When\npresent and non-null, the generator linearly interpolates\nfrom start (week 1) to goal (final week) on the next\nbackfill. When present and null, the goal anchor is cleared\nand the generator reverts to the fixed-rate ramp.\n",
    ),
});

